  SELECT 1 FROM race_catalog c
  WHERE lower(c.name) = lower(v.name)
    AND lower(c.city) = lower(v.city)
    AND c.year = v.year
    AND ROUND(c.dist_km::numeric, 1) = ROUND(v.dist_km::numeric, 1)
);

